files.patch:
@@ -0,0 +1,14 @@
+{
+  "name": "cup_default_home",
+  "description": "CUP with no params defaults to (1,1) i.e. top-left (0,0 zero-indexed)",
+  "initial_size": [5, 3],
+  "input_bytes_hex": "1b5b333b3348581b5b4859",
+  "comment": "CUP(3,3) to (2,2), print X, CUP with no params -> (0,0), print Y; cursor at (0,1)",
+  "expected": {
+    "cursor": { "row": 0, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "Y" },
+      { "row": 2, "col": 2, "char": "X" }
+    ]
+  }
+}

@@ -0,0 +1,13 @@
+{
+  "name": "cup_large_clamp",
+  "description": "CUP with very large coordinates clamps to grid boundaries",
+  "initial_size": [5, 3],
+  "input_bytes_hex": "1b5b3939393b393939485a",
+  "comment": "CUP(999,999) clamps to (2,4) in 5x3 grid, print Z at bottom-right; cursor at (2,4) with pending_wrap",
+  "expected": {
+    "cursor": { "row": 2, "col": 4 },
+    "cells": [
+      { "row": 2, "col": 4, "char": "Z" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "cup_row_only",
+  "description": "CUP with only row param; column defaults to 1 (col 0 zero-indexed)",
+  "initial_size": [5, 3],
+  "input_bytes_hex": "41424344451b5b324846",
+  "comment": "Print ABCDE at row 0, CUP(2) -> row 1 col 0, print F at (1,0); cursor at (1,1)",
+  "expected": {
+    "cursor": { "row": 1, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 0, "col": 4, "char": "E" },
+      { "row": 1, "col": 0, "char": "F" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "reverse_index_at_region_top",
+  "description": "Reverse index (ESC M) at top of scroll region scrolls content down within region",
+  "initial_size": [5, 5],
+  "input_bytes_hex": "1b5b323b34721b5b323b3148411b5b323b31481b4d",
+  "comment": "CSI 2;4 r (region rows 1-3), CUP(2,1) -> (1,0), print A at (1,0), CUP(2,1) -> (1,0) again, ESC M reverse index at region top: blank line at (1,0), A moves to (2,0); cursor at (1,0)",
+  "expected": {
+    "cursor": { "row": 1, "col": 0 },
+    "cells": [
+      { "row": 1, "col": 0, "char": " " },
+      { "row": 2, "col": 0, "char": "A" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "save_restore_with_scroll_region",
+  "description": "Save cursor, set scroll region (which moves cursor to home), restore to saved position",
+  "initial_size": [5, 5],
+  "input_bytes_hex": "1b5b333b33481b371b5b323b34721b5b48411b3842",
+  "comment": "CUP(3,3) -> (2,2), ESC 7 save cursor, CSI 2;4 r set scroll region (cursor goes home), CUP(1,1) -> (0,0), print A at (0,0), ESC 8 restore -> (2,2), print B at (2,2); cursor at (2,3)",
+  "expected": {
+    "cursor": { "row": 2, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 2, "col": 2, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "erase_preserves_nearby_attrs",
+  "description": "Erase-to-end-of-line preserves attributes on cells before the erase point",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b316d41424344451b5b306d1b5b313b33481b5b4b",
+  "comment": "CSI 1 m (bold), print ABCDE (all bold), CSI 0 m reset, CUP(1,3) -> (0,2), CSI K (EL 0 erase right); AB stay bold at cols 0-1, cols 2+ erased; cursor at (0,2)",
+  "expected": {
+    "cursor": { "row": 0, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A", "attrs": { "bold": true } },
+      { "row": 0, "col": 1, "char": "B", "attrs": { "bold": true } },
+      { "row": 0, "col": 2, "char": " ", "attrs": {} }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "sgr_underline_strikethrough_verified",
+  "description": "SGR underline+strikethrough applied and verified on cells, then reset",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b343b396d58591b5b306d5a",
+  "comment": "CSI 4;9 m (underline+strikethrough), print XY, CSI 0 m reset, print Z; cursor at (0,3)",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "X", "attrs": { "underline": true, "strikethrough": true } },
+      { "row": 0, "col": 1, "char": "Y", "attrs": { "underline": true, "strikethrough": true } },
+      { "row": 0, "col": 2, "char": "Z", "attrs": {} }
+    ]
+  }
+}
